mapper.select:
select ci.id, ci.project_id, ci.item_name, ci.item_type, ci.version_no, ci.status, ci.repository_url, ci.remark, ci.created_by, creator.real_name as created_by_name, ci.updated_by, updater.real_name as updated_by_name, ci.created_at, ci.updated_at from config_item ci left join sys_user creator on creator.id = ci.created_by left join sys_user updater on updater.id = ci.updated_by where ci.project_id = #{projectId} and ci.is_deleted = 0
and ( ci.item_name like concat('%', #{query.keyword}, '%') or ci.version_no like concat('%', #{query.keyword}, '%') or ci.repository_url like concat('%', #{query.keyword}, '%') or ci.remark like concat('%', #{query.keyword}, '%') )
and ci.item_type = #{query.itemType}
and ci.status = #{query.status}
order by ci.updated_at desc, ci.created_at desc

mapper.insert:
insert into config_item (
    id, project_id, item_name, item_type, version_no, status, repository_url, remark,
    created_by, created_at, updated_by, updated_at, is_deleted
) values (
    #{id}, #{projectId}, #{itemName}, #{itemType}, #{versionNo}, #{status}, #{repositoryUrl}, #{remark},
    #{createdBy}, #{createdAt}, #{updatedBy}, #{updatedAt}, #{deleted}
)

mapper.update:
update config_item
set is_deleted = 1,
    updated_by = #{updatedBy},
    updated_at = #{updatedAt}
where project_id = #{projectId}
  and id = #{id}
  and is_deleted = 0

update config_item
set is_deleted = 1,
    updated_by = #{updatedBy},
    updated_at = #{updatedAt}
where project_id = #{projectId}
  and is_deleted = 0

mapper.select:
select br.id, br.project_id, br.baseline_type, br.version_no, br.baseline_name, br.snapshot_json, br.status, br.published_by, u.real_name as published_by_name, br.published_at, br.created_at from baseline_record br left join sys_user u on u.id = br.published_by where br.project_id = #{projectId}
and br.baseline_type = #{query.baselineType}
and br.status = #{query.status}
order by br.published_at desc, br.created_at desc, br.id desc

select count(1)
from baseline_record
where project_id = #{projectId}
  and baseline_type = #{baselineType}

mapper.insert:
insert into baseline_record (
    id, project_id, baseline_type, version_no, baseline_name, snapshot_json,
    status, published_by, published_at, created_at
) values (
    #{id}, #{projectId}, #{baselineType}, #{versionNo}, #{baselineName}, #{snapshotJson},
    #{status}, #{publishedBy}, #{publishedAt}, #{createdAt}
)

mapper.delete:
delete from baseline_record
where project_id = #{projectId}
  and id = #{id}
